package org.jsoup.parser;

import cucumber.api.junit.Cucumber;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
public class CucumberTest {
    // This is the Cucumber JUnit runner class
}

package org.jsoup.parser.steps;

import cucumber.api.java.en.Given;
import cucumber.api.java.en.When;
import cucumber.api.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;

import static org.junit.Assert.*;

public class StepDefs {
    private String inputHtml;
    private Document document;
    private Element element;

    @Given("^the input HTML is \"([^\"]*)\"$")
    public void the_input_HTML_is(String html) throws Throwable {
        this.inputHtml = html;
    }

    @When("^the input is parsed$")
    public void the_input_is_parsed() throws Throwable {
        try {
            this.document = Jsoup.parse(inputHtml, "", Parser.htmlParser());
        } catch (Exception e) {
            // Handle any exceptions during parsing
            fail("Exception occurred during parsing: " + e.getMessage());
        }
    }

    @Then("^the document should contain a matching element with the tag name \"([^\"]*)\"$")
    public void the_document_should_contain_a_matching_element_with_the_tag_name(String tagName) throws Throwable {
        // Find element by tag name
        element = document.select(tagName).first();
        assertNotNull("Element with tag name '" + tagName + "' not found", element);
        assertEquals(tagName, element.tagName());
    }

    @Then("^the element text should be \"([^\"]*)\"$")
    public void the_element_text_should_be(String expectedText) throws Throwable {
        assertNotNull("Element was null, cannot check text", element);
        assertEquals("Element text mismatch", expectedText, element.text());
    }
}

